// Decode base64 and add line numbers for QA

const fileContent = $input.first().json.content;
const fileEncoding = $input.first().json.encoding;
const fileSha = $input.first().json.sha;
const filePath = $input.first().json.path;

let decodedContent = fileContent;
if (fileEncoding === 'base64') {
  decodedContent = Buffer.from(fileContent, 'base64').toString('utf-8');
}

const lines = decodedContent.split('\n');
const numberedLines = lines.map((line, index) => {
  const lineNumber = index + 1;
  return `${lineNumber}: ${line}`;
});
const numberedContent = numberedLines.join('\n');

return {
  json: {
    originalContent: decodedContent,
    numberedContent: numberedContent,
    lineCount: lines.length,
    sha: fileSha,
    path: filePath
  }
};

// Parse QA output and filter to high/medium severity only

const qaAgentResponse = $input.first().json.output;

let cleanedResponse = qaAgentResponse.trim();
if (cleanedResponse.startsWith('```json')) {
  cleanedResponse = cleanedResponse.slice(7);
}
if (cleanedResponse.startsWith('```')) {
  cleanedResponse = cleanedResponse.slice(3);
}
if (cleanedResponse.endsWith('```')) {
  cleanedResponse = cleanedResponse.slice(0, -3);
}
cleanedResponse = cleanedResponse.trim();

try {
  const allIssues = JSON.parse(cleanedResponse);

  if (!Array.isArray(allIssues)) {
    throw new Error('QA output is not an array');
  }

  const validIssues = allIssues.filter(issue => {
    const hasLineNumber = issue.line_number && typeof issue.line_number === 'number';
    const hasIssueType = issue.issue_type;
    const hasDescription = issue.description;
    const isHighOrMedium = issue.severity === 'high' || issue.severity === 'medium';

    return hasLineNumber && hasIssueType && hasDescription && isHighOrMedium;
  });

  const originalContent = $('Decode Base64 & Add Line Numbers').first().json.originalContent;
  const fileSha = $('Decode Base64 & Add Line Numbers').first().json.sha;
  const filePath = $('Decode Base64 & Add Line Numbers').first().json.path;

  return {
    json: {
      issues: validIssues,
      issueCount: validIssues.length,
      originalContent: originalContent,
      sha: fileSha,
      path: filePath,
      parseSuccess: true
    }
  };

} catch (error) {
  return {
    json: {
      issues: [],
      issueCount: 0,
      parseError: error.message,
      rawResponse: qaAgentResponse,
      parseSuccess: false
    }
  };
}

// Parse editor output and sort edits descending (bottom-to-top)

const editorAgentResponse = $input.first().json.output;

let cleanedResponse = editorAgentResponse.trim();
if (cleanedResponse.startsWith('```json')) {
  cleanedResponse = cleanedResponse.slice(7);
}
if (cleanedResponse.startsWith('```')) {
  cleanedResponse = cleanedResponse.slice(3);
}
if (cleanedResponse.endsWith('```')) {
  cleanedResponse = cleanedResponse.slice(0, -3);
}
cleanedResponse = cleanedResponse.trim();

try {
  const editOperations = JSON.parse(cleanedResponse);

  if (!Array.isArray(editOperations)) {
    throw new Error('Editor output is not an array');
  }

  const sortedEdits = editOperations.sort((a, b) => {
    return b.line_number - a.line_number;
  });

  const originalContent = $('Parse QA Issues JSON').first().json.originalContent;
  const fileSha = $('Parse QA Issues JSON').first().json.sha;
  const filePath = $('Parse QA Issues JSON').first().json.path;
  const issues = $('Parse QA Issues JSON').first().json.issues;

  return {
    json: {
      edits: sortedEdits,
      editCount: sortedEdits.length,
      originalContent: originalContent,
      sha: fileSha,
      path: filePath,
      issues: issues,
      parseSuccess: true
    }
  };

} catch (error) {
  return {
    json: {
      edits: [],
      editCount: 0,
      parseError: error.message,
      rawResponse: editorAgentResponse,
      parseSuccess: false
    }
  };
}

// Apply edits to content, skip invalid lines, track success rate

const originalContent = $input.first().json.originalContent;
const editOperations = $input.first().json.edits;
const fileSha = $input.first().json.sha;
const filePath = $input.first().json.path;
const issues = $input.first().json.issues;

let lines = originalContent.split('\n');
const totalLines = lines.length;

editOperations.sort((a, b) => b.line_number - a.line_number);

let appliedCount = 0;
let skippedCount = 0;
const appliedChanges = [];
const skippedChanges = [];

for (const edit of editOperations) {
  const arrayIndex = edit.line_number - 1;

  if (arrayIndex < 0 || arrayIndex >= totalLines) {
    skippedCount++;
    skippedChanges.push({
      line: edit.line_number,
      reason: 'Line number out of range'
    });
    continue;
  }

  if (edit.operation === 'replace') {
    appliedChanges.push({
      line: edit.line_number,
      operation: 'replace',
      oldText: lines[arrayIndex],
      newText: edit.new_text
    });
    lines[arrayIndex] = edit.new_text;
    appliedCount++;

  } else if (edit.operation === 'insert_after') {
    appliedChanges.push({
      line: edit.line_number,
      operation: 'insert_after',
      insertedText: edit.new_text
    });
    lines.splice(arrayIndex + 1, 0, edit.new_text);
    appliedCount++;

  } else if (edit.operation === 'delete') {
    appliedChanges.push({
      line: edit.line_number,
      operation: 'delete',
      deletedText: lines[arrayIndex]
    });
    lines.splice(arrayIndex, 1);
    appliedCount++;

  } else {
    skippedCount++;
    skippedChanges.push({
      line: edit.line_number,
      reason: 'Unknown operation: ' + edit.operation
    });
  }
}

const totalEdits = appliedCount + skippedCount;
const successRate = totalEdits > 0 ? appliedCount / totalEdits : 1;
const isSuccess = successRate >= 0.5 && appliedCount > 0;
const updatedContent = lines.join('\n');

return {
  json: {
    updatedContent: updatedContent,
    sha: fileSha,
    path: filePath,
    issues: issues,
    applied: appliedCount,
    skipped: skippedCount,
    successRate: successRate,
    success: isSuccess,
    appliedChanges: appliedChanges,
    skippedChanges: skippedChanges
  }
};

// Build markdown report with applied changes

const issues = $input.first().json.issues;
const appliedChanges = $input.first().json.appliedChanges;
const skippedChanges = $input.first().json.skippedChanges;
const successRate = $input.first().json.successRate;
const fileSha = $input.first().json.sha;
const filePath = $input.first().json.path;
const updatedContent = $input.first().json.updatedContent;
const isSuccess = $input.first().json.success;

const today = new Date().toISOString().slice(0, 10);

let report = '';
report += `# QA Report - ${today}\n\n`;
report += `## Summary\n`;
report += `- Applied: ${appliedChanges.length}\n`;
report += `- Skipped: ${skippedChanges.length}\n`;
report += `- Success Rate: ${(successRate * 100).toFixed(0)}%\n\n`;

report += `## Issues Found\n\n`;
for (const issue of issues) {
  report += `### Line ${issue.line_number} (${issue.issue_type})\n`;
  report += `${issue.description}\n\n`;
}

report += `## Changes Applied\n\n`;
for (const change of appliedChanges) {
  report += `- Line ${change.line}: ${change.operation}\n`;
}

if (skippedChanges.length > 0) {
  report += `\n## Skipped Edits\n\n`;
  for (const skip of skippedChanges) {
    report += `- Line ${skip.line}: ${skip.reason}\n`;
  }
}

return {
  json: {
    report: report,
    sha: fileSha,
    path: filePath,
    updatedContent: updatedContent,
    success: isSuccess
  }
};

// Report when no issues found

const today = new Date().toISOString().slice(0, 10);
const filePath = $('Parse QA Issues JSON').first().json.path;

let report = '';
report += `# QA Report - ${today}\n\n`;
report += `## Summary\n`;
report += `✅ No issues detected\n\n`;
report += `The blog post passed QA review with no changes required.\n`;

return {
  json: {
    report: report,
    path: filePath
  }
};

// Report when edits failed to apply

const skippedChanges = $input.first().json.skippedChanges || [];
const appliedCount = $input.first().json.applied || 0;
const skippedCount = $input.first().json.skipped || 0;
const successRate = $input.first().json.successRate || 0;

const today = new Date().toISOString().slice(0, 10);

let report = '';
report += `# QA Report - ${today}\n\n`;
report += `## ⚠️ Commit Skipped\n\n`;
report += `The edits could not be safely applied. No changes were made to the file.\n\n`;
report += `## Summary\n`;
report += `- Applied: ${appliedCount}\n`;
report += `- Skipped: ${skippedCount}\n`;
report += `- Success Rate: ${(successRate * 100).toFixed(0)}%\n\n`;

if (skippedChanges.length > 0) {
  report += `## Skipped Edits\n\n`;
  for (const skip of skippedChanges) {
    report += `- Line ${skip.line}: ${skip.reason}\n`;
  }
}

report += `\n## Next Steps\n`;
report += `- Review the QA issues manually\n`;
report += `- Check if line numbers are correct\n`;
report += `- Re-run the workflow after fixing the source content\n`;

return {
  json: {
    report: report,
    path: $input.first().json.path
  }
};
